import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';

import Logo from '../Assets/TopherEmbyLogo.png';
import TopherEmby from './TopherEmby';

const BoxWithHover = styled(Box)`
  &:hover img {
    animation: spin 0.5s linear 1;
  }

  @keyframes spin {
    from {
      transform: rotate(0deg);
    }
    to {
      transform: rotate(360deg);
    }
  }
`;
const openPdf = () => {
    window.open(<TopherEmby/>);
  }

const projectItem = (image, name, func) => {
  return (
    <Container
      maxWidth='none'
      onClick={func}
      sx={{
        display: 'flex', 
        flexDirection: 'row', 
        alignItems: 'center',
        width: '100%',
        mx: 'auto',
        mb: '25vh',
        cursor: 'pointer'
      }}       
    >
      <BoxWithHover>
        <Box 
          component='img'
          src={image}
          alt={`${name} logo`}
          href={<TopherEmby/>}
          sx={{
            height: '10vw',
            mr: 2,
          }}
        />
      </BoxWithHover>
      <Typography variant='h3' onClick={openPdf}>{name}</Typography>
    </Container>
  );
};

function Projects () {
    const navigate = useNavigate();
    const reroute = (path) => {
        return () => navigate(path);
    };
    const openPdf = () => {
        window.open(<TopherEmby/>, '_blank');
      }

    return (
        <Container
          maxWidth='none'
          sx={{
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center',
            width: '100%',
            mx: 'auto',
            mb: '25vh'
          }}        
        >
            <Typography 
              id='projects'
              variant='h2' 
              my={4}
            >
              Projects
            </Typography>
            <Box sx={{ display: 'flex', justifyContent: 'center' }}>
              {/* {projectItem(Logo, 'Topher Emby', reroute('/TopherEmby'))} */}
              {projectItem(Logo, 'Topher Emby' )}
            </Box>
        </Container>
    );
}

export default Projects;
